import{_ as o,c as s,o as n,U as t}from"./chunks/framework.9QHaLlVJ.js";const p=JSON.parse('{"title":"known_hosts和known_hosts.old","description":"","frontmatter":{},"headers":[],"relativePath":"doc/平台/通用组件/ssh/known_hosts.md","filePath":"packages/doc/src/平台/通用组件/ssh/known_hosts.md","lastUpdated":1704615314000}'),a={name:"doc/平台/通用组件/ssh/known_hosts.md"},h=t('<h1 id="known-hosts和known-hosts-old" tabindex="-1">known_hosts和known_hosts.old <a class="header-anchor" href="#known-hosts和known-hosts-old" aria-label="Permalink to &quot;known_hosts和known_hosts.old&quot;">​</a></h1><p>known_hosts和known_hosts.old是SSH客户端中的文件，用于存储已知主机的公钥信息。</p><p>以下是它们的作用和功能：</p><h2 id="known-hosts文件" tabindex="-1">known_hosts文件 <a class="header-anchor" href="#known-hosts文件" aria-label="Permalink to &quot;known_hosts文件&quot;">​</a></h2><p>这个文件包含了您曾经连接过的远程主机的公钥信息。</p><p>当您首次连接一个远程主机时，SSH客户端会将该主机的公钥保存在known_hosts文件中。 下次再次连接该主机时，客户端会验证主机的公钥是否与之前保存的一致，以防止中间人攻击。如果主机的公钥发生变化，客户端会发出警告，以提醒您进行确认。</p><h2 id="known-hosts-old文件" tabindex="-1">known_hosts.old文件 <a class="header-anchor" href="#known-hosts-old文件" aria-label="Permalink to &quot;known_hosts.old文件&quot;">​</a></h2><p>当SSH客户端检测到known_hosts文件发生了变化（比如主机公钥发生了更改）时，它会将原始的known_hosts文件备份为known_hosts.old。 这样，您可以在需要时恢复到旧的已知主机配置。</p><p>这些文件通常位于SSH客户端用户的~/.ssh/目录下，每个用户都有自己的独立副本。</p><p>请注意，known_hosts文件不包含任何敏感信息，它只存储了公钥信息以供身份验证使用。</p><p>但是，如果您的系统存在安全问题，有人可能会通过欺骗您来窃取您的密钥，因此当发现known_hosts文件发生变化时，务必审查和验证公钥的有效性。</p><h2 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h2><ul><li>该文件位于客户端用户的~/.ssh/目录下，每个用户都有自己的独立副本。</li><li>用来验证远程主机身份</li></ul>',13),e=[h];function _(l,d,r,k,i,c){return n(),s("div",null,e)}const u=o(a,[["render",_]]);export{p as __pageData,u as default};
